create table public.demo_space_operators(id uuid primary key default gen_random_uuid(),name text not null,created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.spaces(id uuid primary key default gen_random_uuid(),operator_id uuid references public.demo_space_operators(id) on delete set null,name text not null,slug text unique not null,space_type text not null,short_description text,description text,main_region text not null,detailed_region text,address text not null,address_detail text,price_per_hour integer not null check(price_per_hour>=0),minimum_hours integer not null default 1 check(minimum_hours>=1),suitable_capacity integer,max_capacity integer not null check(max_capacity>=1),available_days text[] not null default '{}',available_start_time time,available_end_time time,regular_use_available boolean not null default false,facilities text[] not null default '{}',moods text[] not null default '{}',suitable_activities text[] not null default '{}',noise_level text not null default 'moderate' check(noise_level in('quiet','moderate','active')),food_allowed boolean not null default false,alcohol_allowed boolean not null default false,furniture_movable boolean not null default false,parking_available boolean not null default false,thumbnail_url text,status text not null default 'draft' check(status in('draft','active','inactive')),created_at timestamptz not null default now(),updated_at timestamptz not null default now());
create table public.space_images(id uuid primary key default gen_random_uuid(),space_id uuid not null references public.spaces(id) on delete cascade,storage_path text not null unique,public_url text not null,file_name text,mime_type text,file_size integer,width integer,height integer,sort_order integer not null default 0,is_thumbnail boolean not null default false,created_at timestamptz not null default now());
create unique index one_space_thumbnail on public.space_images(space_id) where is_thumbnail=true;
create trigger demo_space_operators_updated before update on public.demo_space_operators for each row execute function public.set_updated_at();
create trigger spaces_updated before update on public.spaces for each row execute function public.set_updated_at();
create index spaces_status_idx on public.spaces(status);create index spaces_main_region_idx on public.spaces(main_region);create index spaces_detailed_region_idx on public.spaces(detailed_region);create index spaces_type_idx on public.spaces(space_type);create index spaces_created_idx on public.spaces(created_at desc);create index space_images_space_idx on public.space_images(space_id);create index space_images_order_idx on public.space_images(space_id,sort_order);
alter table public.demo_space_operators enable row level security;alter table public.spaces enable row level security;alter table public.space_images enable row level security;
create policy "active spaces public read" on public.spaces for select to anon using(status='active');
create policy "active space images public read" on public.space_images for select to anon using(exists(select 1 from public.spaces s where s.id=space_id and s.status='active'));
grant select on public.spaces,public.space_images to anon;grant all on public.demo_space_operators,public.spaces,public.space_images to service_role;
insert into storage.buckets(id,name,public,file_size_limit,allowed_mime_types) values('space-images','space-images',true,5242880,array['image/jpeg','image/png','image/webp']) on conflict(id) do update set public=true,file_size_limit=excluded.file_size_limit,allowed_mime_types=excluded.allowed_mime_types;
create policy "public reads space images bucket" on storage.objects for select to anon using(bucket_id='space-images');
